138→func extractLocation(data map[string]any) *model.InstitutionLocation {
139→	nces := jsonbObject(data, "nces")
140→	metro := jsonbObject(data, "metro_area")
141→
142→	loc := &model.InstitutionLocation{}
143→	if nces != nil {
144→		loc.Locale = jsonbString(nces, "locale")
145→		loc.Region = jsonbString(nces, "region_id")
146→	}
147→	if metro != nil {
148→		loc.MetroArea = jsonbString(metro, "name")
149→		loc.MetroDistance = jsonbFloat(metro, "distance")
150→	}

380→func extractMeta(data map[string]any) *model.InstitutionMeta {
381→	nces := jsonbObject(data, "nces")
382→	if nces == nil {
383→		return nil
384→	}
385→
386→	m := &model.InstitutionMeta{
387→		SchoolURL:  jsonbString(nces, "school_url"),
388→		Accreditor: jsonbString(nces, "accreditor"),
389→	}
390→	if m.SchoolURL == nil && m.Accreditor == nil {
391→		return nil
392→	}
393→	return m
394→}
